import{_ as r,o as a,c as e,ae as l}from"./chunks/framework.DrYEjkpc.js";const k=JSON.parse('{"title":"EvoSkills / CoEvoSkills","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-evoskills.md","filePath":"radar/tech-evoskills.md"}'),o={name:"radar/tech-evoskills.md"};function i(s,t,n,h,d,u){return a(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="evoskills-coevoskills" tabindex="-1">EvoSkills / CoEvoSkills <a class="header-anchor" href="#evoskills-coevoskills" aria-label="Permalink to &quot;EvoSkills / CoEvoSkills&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 生成 / Skill 评测 | <strong>成熟度</strong>: 🟡 成长期 | <strong>综合评分</strong>: 0.53</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: <strong>协同进化 + 两层验证</strong>架构（Surrogate Verifier + Ground-truth Oracle），自生成 Skill 通过率 <strong>75% vs Skill Creator 基线 34.1%</strong>。</p><p><strong>来源</strong>:</p><ul><li>学术研究</li><li>论文 + 官网</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2604.01687" target="_blank" rel="noreferrer">arXiv 2604.01687</a></li><li>GitHub：<a href="https://github.com/Zhang-Henry/CoEvoSkills" target="_blank" rel="noreferrer">Zhang-Henry/CoEvoSkills</a></li><li>官网：<a href="https://evoskills.net/" target="_blank" rel="noreferrer">evoskills.net</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="核心原理-两层验证" tabindex="-1">核心原理：两层验证 <a class="header-anchor" href="#核心原理-两层验证" aria-label="Permalink to &quot;核心原理：两层验证&quot;">​</a></h3><table tabindex="0"><thead><tr><th>层</th><th>角色</th><th>反馈类型</th></tr></thead><tbody><tr><td><strong>Surrogate Verifier</strong></td><td>信息隔离的独立 LLM 会话，主动生成测试断言 + 结构化失败诊断</td><td>密集但可能不准确</td></tr><tr><td><strong>Ground-truth Oracle</strong></td><td>全新环境中重新执行 Skill</td><td>稀疏但准确（不透明 pass/fail）</td></tr></tbody></table><p>消融实验：去掉 Surrogate Verifier，通过率从 71.1% 暴跌至 41.1% —— oracle 的 pass/fail 信号远远不够。</p><h3 id="协同进化的典型轨迹" tabindex="-1">协同进化的典型轨迹 <a class="header-anchor" href="#协同进化的典型轨迹" aria-label="Permalink to &quot;协同进化的典型轨迹&quot;">​</a></h3><p>系外行星公转周期检测任务中，Generator 最初用 BLS 算法 → Surrogate 反馈精度不足 → 调参两轮无效 → Generator 切换到 TLS + 两阶段搜索 → 100% 通过率。<strong>驱动了方法论级创新</strong>，而非仅调参。</p><h3 id="跨模型迁移" tabindex="-1">跨模型迁移 <a class="header-anchor" href="#跨模型迁移" aria-label="Permalink to &quot;跨模型迁移&quot;">​</a></h3><p>Claude Opus 4.6 上进化的 Skill 迁移到另外 6 个模型，均获得 +36-44pp 提升 —— Skill 编码的是任务结构，而非模型偏好。</p><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li><strong>并未真正去掉 ground-truth</strong> —— Surrogate 降低了对人工验证的依赖，但 oracle 层仍需正确性判断</li><li><strong>Surrogate 的判断力上限 = LLM 自身领域知识</strong> —— 对运维、医疗、法律等深度领域可能无法生成有效断言</li><li>仍有 25% 失败</li><li>计算成本较高（多轮迭代 × 多次验证）</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.55</td><td>论文 + 开源 + 官网</td></tr><tr><td>创新性</td><td>0.85</td><td>两层验证 + 协同进化是范式级突破</td></tr><tr><td>落地程度</td><td>0.30</td><td>研究阶段</td></tr><tr><td>生态活跃度</td><td>0.40</td><td>学术社区关注度高</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.53</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2604.01687" target="_blank" rel="noreferrer">EvoSkills 论文</a></li><li><a href="https://github.com/Zhang-Henry/CoEvoSkills" target="_blank" rel="noreferrer">GitHub - CoEvoSkills</a></li><li><a href="https://evoskills.net/" target="_blank" rel="noreferrer">官网</a></li></ul>',29)])])}const c=r(o,[["render",i]]);export{k as __pageData,c as default};
